var cheap = cheapLegals(leg);
if (cheap.length) {
  if (handLen >= 7 && omin >= 4 && curTop < 10 && !playIsBomb(cur.cards||[])) {
    var pool = cheap.filter(function(p){ var c=detectCombo(p); return c && c.type===cur.type; });
    if (pool.length >= 2) {
      pool.sort(function(a,b){
        var sa=structureBreakCost(hand,a), sb=structureBreakCost(hand,b);
        if (sa!==sb) return sa-sb;
        // residual pairs / maxRun tertiary (see NOTE-w24-architecture-levers)
        return expertScore(a,state,cp)-expertScore(b,state,cp);
      });
      return { play: pool[0] };
    }
  }
  return { play: orderLegals(cheap,state,cp)[0] };
}
